const items = $input.all();
let messages = [];

// 1. Normaliza a entrada: aceita tanto um único item quanto uma lista
items.forEach(item => {
  const json = item.json;
  if (Array.isArray(json)) {
    messages.push(...json);
  } else if (json.messages && Array.isArray(json.messages)) {
    messages.push(...json.messages);
  } else {
    messages.push(json);
  }
});

const mapped = messages.map(item => {
  // 2. Extrai os dados internos (suporta o formato 'body.data' ou direto)
  const innerData = item.body?.data || item.data || item;

  // 3. Extrai o conteúdo da mensagem
  const msgObj = innerData.message?.message || innerData.message || {};

  // 4. Busca o texto
  const text = msgObj.conversation || 
               msgObj.extendedTextMessage?.text || 
               msgObj.imageMessage?.caption || 
               innerData.content ||
               "";

  if (!text || text.trim() === "") return null;

  return {
    body: {
      data: {
        key: { id: innerData.key?.id || Math.random().toString() },
        pushName: innerData.pushName || "Cliente WhatsApp",
        message: { conversation: text }
      },
      date_time: item.body?.date_time || item.date_time || (innerData.messageTimestamp ? new Date(innerData.messageTimestamp * 1000).toISOString() : new Date().toISOString())
    }
  };
}).filter(i => i !== null);

return mapped;
